const email = $input.first().json;
const binaryKeys = Object.keys($input.first().binary || {});

// Find the first attachment that looks like a resume file
const resumeKey = binaryKeys.find(k => {
  const fileName = ($input.first().binary[k]?.fileName || '').toLowerCase();
  return fileName.endsWith('.pdf') || fileName.endsWith('.doc') || fileName.endsWith('.docx');
});

if (!resumeKey) {
  return [{
    json: {
      noResumeFound: true,
      from: email.from,
      subject: email.subject
    }
  }];
}

const fileName = $input.first().binary[resumeKey].fileName || '';
const isPdf = fileName.toLowerCase().endsWith('.pdf');

return [{
  json: {
    from: email.from,
    subject: email.subject,
    body: email.text || '',
    filename: fileName,
    isPdf,
    resumeBinaryKey: resumeKey,
    receivedAt: email.date || new Date().toISOString()
  },
  binary: {
    resume: $input.first().binary[resumeKey]
  }
}];

// Defensive JSON parsing -- handle markdown code fences, partial JSON, and missing fields
const raw = $json.message?.content || $json.text || $json.output || '';

let parsed;
try {
  const cleaned = raw.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  return [{
    json: {
      parseFailed: true,
      rawOutput: raw,
      from: $('Extract Resume').item.json.from,
      filename: $('Extract Resume').item.json.filename
    }
  }];
}

return [{
  json: {
    parseFailed: false,
    name: parsed.name || 'Unknown Candidate',
    email: parsed.email || null,
    phone: parsed.phone || null,
    skills: Array.isArray(parsed.skills) ? parsed.skills : [],
    experience_years: typeof parsed.experience_years === 'number' ? parsed.experience_years : null,
    education: parsed.education || null,
    current_title: parsed.current_title || null,
    companies: Array.isArray(parsed.companies) ? parsed.companies : [],
    applicantEmail: $('Extract Resume').item.json.from,
    filename: $('Extract Resume').item.json.filename
  }
}];

